        correctVerseMeaningTranslations: { en: "The day when the quaking blast quakes, followed by the following blast", ar: "\u064A\u0648\u0645 \u062A\u0631\u062C\u0641 \u0627\u0644\u0631\u0627\u062C\u0641\u0629 \u062A\u062A\u0628\u0639\u0647\u0627 \u0627\u0644\u0631\u0627\u062F\u0641\u0629", id: "Pada hari ketika tiupan pertama mengguncang, disusul tiupan berikutnya", tr: "Sars\u0131nt\u0131n\u0131n sarst\u0131\u011F\u0131 g\xFCn, ard\u0131ndan gelenin takip etti\u011Fi g\xFCn", zh: "\u90A3\u5929\uFF0C\u9707\u52A8\u8005\u9707\u52A8\uFF0C\u968F\u540E\u968F\u884C\u8005\u968F\u6765", sw: "Siku gongo la kwanza litatikisika, likifuatiwa na pigo la pili", so: "Maalinta Xididaagu gariirto ka dibna Raadifdaagu raacdo", bs: "Na dan kada potres zatre, za njim do\u0111e ona koja slijedi", sq: "Dit\xEBn kur t\xEBrmeti trondit, pasohet nga ajo q\xEB vjen pas", ru: "\u0412 \u0434\u0435\u043D\u044C, \u043A\u043E\u0433\u0434\u0430 \u0441\u043E\u0442\u0440\u044F\u0441\u0430\u044E\u0449\u0435\u0435 \u043F\u043E\u0442\u0440\u044F\u0441\u0451\u0442, \u0437\u0430 \u043D\u0435\u0439 \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435", ur: "\u0627\u0633 \u062F\u0646 \u062C\u0628 \u067E\u06C1\u0644\u06CC \u0635\u06CC\u062D\u0629 \u06A9\u0627\u0646\u067E\u0627\u0626\u06D2 \u06AF\u06CC\u060C \u067E\u06BE\u0631 \u062F\u0648\u0633\u0631\u06CC \u0622\u0626\u06D2 \u06AF\u06CC", bn: "\u09AF\u09C7\u09A6\u09BF\u09A8 \u0995\u09AE\u09CD\u09AA\u09A8\u0995\u09BE\u09B0\u09C0 \u0995\u09BE\u0981\u09AA\u09AC\u09C7 \u09A4\u09BE\u09B0\u09AA\u09B0 \u09AA\u09B0\u09AC\u09B0\u09CD\u09A4\u09C0 \u09AC\u09BF\u09B8\u09CD\u09AB\u09CB\u09B0\u09A3 \u09B9\u09AC\u09C7", ms: "Pada hari ketika gegaran yang menggegar, diikuti oleh yang mengikutinya" },
        surahAyah: "\u0627\u0644\u0646\u0627\u0632\u0639\u0627\u062A:7",
