        hint: "\u0645\u0627 \u064A\u0623\u062A\u064A \u0641\u064A \u0627\u0644\u0645\u0631\u062A\u0628\u0629 \u0627\u0644\u062B\u0627\u0646\u064A\u0629 \u0628\u0639\u062F \u0627\u0644\u0623\u0648\u0644\u0649",
        correctVerse: "\u062A\u064E\u062A\u0652\u0628\u064E\u0639\u064F\u0647\u064E\u0627 \u0627\u0644\u0631\u064E\u0651\u0627\u062F\u0650\u0641\u064E\u0629\u064F",
        correctVerseMeaning: "Followed by the following blast",
