        correctVerseMeaningTranslations: { en: "And by the night as it departs", ar: "\u0648\u0627\u0644\u0644\u064A\u0644 \u0625\u0630\u0627 \u0639\u0633\u0639\u0633", id: "Dan demi malam apabila berlalu", tr: "Geceye yemin olsun, \xE7ekildi\u011Finde", zh: "\u4EE5\u591C\u5E55\u9000\u53BB\u65F6\u4E3A\u8A93", sw: "Na usiku unapoondoka", so: "Habeenkana marka uu baxo", bs: "I no\u0107u kada se povu\u010De", sq: "Dhe naten kur t\xEB t\xEBrhiqet", ru: "\u0418 \u043D\u043E\u0447\u044C\u044E, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u043E\u0442\u0441\u0442\u0443\u043F\u0430\u0435\u0442", ur: "\u0627\u0648\u0631 \u0631\u0627\u062A \u06A9\u06CC \u0642\u0633\u0645 \u062C\u0628 \u067E\u06CC\u0679\u06BE \u067E\u06BE\u06CC\u0631\u06D2", bn: "\u09B0\u09BE\u09A4\u09C7\u09B0 \u09B6\u09AA\u09A5 \u09AF\u0996\u09A8 \u09B8\u09C7 \u09AA\u09CD\u09B0\u09B8\u09CD\u09A5\u09BE\u09A8 \u0995\u09B0\u09C7", ms: "Dan demi malam apabila berlalu" },
