        targetWordTranslations: { en: "The Righteous", ar: "\u0627\u0644\u0635\u0627\u0644\u062D\u0648\u0646 \u0627\u0644\u0645\u0637\u064A\u0639\u0648\u0646", id: "Orang-orang yang berbakti", tr: "\u0130yiler / Erdemliler", zh: "\u5584\u826F\u4E4B\u4EBA", sw: "Watu wema", so: "Kuwa fiicanka", bs: "Pravednici", sq: "T\xEB mir\xEBt / T\xEB drejt\xEBt", ru: "\u041F\u0440\u0430\u0432\u0435\u0434\u043D\u0438\u043A\u0438", ur: "\u0646\u06CC\u06A9 \u0644\u0648\u06AF", bn: "\u09B8\u09CE\u0995\u09B0\u09CD\u09AE\u09B6\u09C0\u09B2\u0997\u09A3", ms: "Orang-orang yang baik" },
        correctVerseMeaningTranslations: { en: "Indeed, the righteous will be in bliss", ar: "\u0625\u0646 \u0627\u0644\u0623\u0628\u0631\u0627\u0631 \u0644\u0641\u064A \u0646\u0639\u064A\u0645", id: "Sesungguhnya orang-orang yang berbakti benar-benar dalam kenikmatan", tr: "\u0130yiler ger\xE7ekten nimette olacak", zh: "\u5584\u4EBA\u786E\u5728\u5E78\u798F\u4E4B\u4E2D", sw: "Hakika watu wema watakuwa katika neema", so: "Runtii, Kuwa fiicanka waxay ku jiraan raaxo", bs: "Zaista, pravednici su u blagostanju", sq: "Me t\xEB v\xEBrtet\xEB, t\xEB mir\xEBt do t\xEB jen\xEB n\xEB begati", ru: "\u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u043F\u0440\u0430\u0432\u0435\u0434\u043D\u0438\u043A\u0438 \u0431\u0443\u0434\u0443\u0442 \u0432 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0435", ur: "\u0628\u06D2 \u0634\u06A9 \u0646\u06CC\u06A9 \u0644\u0648\u06AF \u0646\u0639\u0645\u062A\u0648\u06BA \u0645\u06CC\u06BA \u06C1\u0648\u06BA \u06AF\u06D2", bn: "\u09A8\u09BF\u09B6\u09CD\u099A\u09AF\u09BC\u0987 \u09B8\u09CE\u0995\u09B0\u09CD\u09AE\u09B6\u09C0\u09B2\u0997\u09A3 \u09B8\u09C1\u0996\u09C7 \u09A5\u09BE\u0995\u09AC\u09C7", ms: "Sesungguhnya orang-orang yang baik berada dalam kenikmatan" },
