        correctVerseMeaningTranslations: { en: "And indeed, the wicked will be in a blazing fire", ar: "\u0648\u0625\u0646 \u0627\u0644\u0641\u062C\u0627\u0631 \u0644\u0641\u064A \u062C\u062D\u064A\u0645", id: "Dan sesungguhnya orang-orang fasik benar-benar dalam neraka", tr: "Ve g\xFCnahk\xE2rlar ger\xE7ekten cehennemdedir", zh: "\u90AA\u6076\u8005\u786E\u5728\u718A\u718A\u70C8\u706B\u4E4B\u4E2D", sw: "Na hakika waovu watakuwa katika moto mkali", so: "Runtii Fujaarada waxay ku jiraan naareey", bs: "I zaista, grje\u0161nici su u paklu", sq: "Dhe me t\xEB v\xEBrtet\xEB, m\xEBkatar\xEBt do t\xEB jen\xEB n\xEB zjarr", ru: "\u0418 \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 \u043D\u0435\u0447\u0435\u0441\u0442\u0438\u0432\u0446\u044B \u0432 \u0430\u0434\u0441\u043A\u043E\u043C \u043E\u0433\u043D\u0435", ur: "\u0627\u0648\u0631 \u0628\u06D2 \u0634\u06A9 \u0641\u0627\u062C\u0631 \u0644\u0648\u06AF \u062C\u06C1\u0646\u0645 \u0645\u06CC\u06BA \u06C1\u0648\u06BA \u06AF\u06D2", bn: "\u098F\u09AC\u0982 \u09A8\u09BF\u09B6\u09CD\u099A\u09AF\u09BC\u0987 \u09AA\u09BE\u09AA\u09C0\u09B0\u09BE \u099C\u09BE\u09B9\u09BE\u09A8\u09CD\u09A8\u09BE\u09AE\u09C7 \u09A5\u09BE\u0995\u09AC\u09C7", ms: "Dan sesungguhnya orang-orang jahat berada dalam neraka" },
