        targetWordMeaning: "Those Who Give Short Measure",
        targetWordTranslations: { en: "Those Who Give Short Measure", ar: "\u0627\u0644\u0645\u0646\u0642\u0635\u0648\u0646 \u0641\u064A \u0627\u0644\u0643\u064A\u0644 \u0648\u0627\u0644\u0648\u0632\u0646", id: "Orang yang curang dalam timbangan", tr: "\xD6l\xE7\xFCde eksiklik yapanlar", zh: "\u77ED\u65A4\u7F3A\u4E24\u8005", sw: "Wale wanaopunguza vipimo", so: "Kuwa Ceebaaya Miisaanka", bs: "Oni koji kratko mjere", sq: "Ata q\xEB mashtroisin n\xEB matje", ru: "\u0422\u0435, \u043A\u0442\u043E \u043E\u0431\u043C\u0435\u0440\u0438\u0432\u0430\u044E\u0442 / \u043E\u0431\u0432\u0435\u0448\u0438\u0432\u0430\u044E\u0442", ur: "\u0646\u0627\u067E \u062A\u0648\u0644 \u0645\u06CC\u06BA \u0688\u0646\u0688\u06CC \u0645\u0627\u0631\u0646\u06D2 \u0648\u0627\u0644\u06D2", bn: "\u09AF\u09BE\u09B0\u09BE \u09AE\u09BE\u09AA\u09C7 \u0995\u09AE \u09A6\u09C7\u09AF\u09BC", ms: "Orang-orang yang curang dalam sukatan" },
        correctVerseMeaningTranslations: { en: "Woe to those who give short measure", ar: "\u0648\u064A\u0644 \u0644\u0644\u0645\u0637\u0641\u0641\u064A\u0646", id: "Kecelakaan besar bagi orang-orang yang curang", tr: "\xD6l\xE7\xFCde eksiklik yapanlara yaz\u0131klar olsun", zh: "\u7978\u54C9\uFF0C\u90A3\u4E9B\u77ED\u65A4\u7F3A\u4E24\u8005", sw: "Ole wao wanaopunguza vipimo", so: "Ceeb ku tahay kuwa Ceebeeya Miisaanka", bs: "Te\u0161ko onima koji kratko mjere", sq: "Mjer\xEB ata q\xEB mashtroisin n\xEB matje", ru: "\u0413\u043E\u0440\u0435 \u043E\u0431\u043C\u0435\u0440\u0438\u0432\u0430\u044E\u0449\u0438\u043C", ur: "\u0646\u0627\u067E \u062A\u0648\u0644 \u0645\u06CC\u06BA \u0688\u0646\u0688\u06CC \u0645\u0627\u0631\u0646\u06D2 \u0648\u0627\u0644\u0648\u06BA \u06A9\u06D2 \u0644\u06CC\u06D2 \u062E\u0631\u0627\u0628\u06CC \u06C1\u06D2", bn: "\u09A6\u09C1\u09B0\u09CD\u09AD\u09CB\u0997 \u09A4\u09BE\u09A6\u09C7\u09B0 \u099C\u09A8\u09CD\u09AF \u09AF\u09BE\u09B0\u09BE \u09AE\u09BE\u09AA\u09C7 \u0995\u09AE \u09A6\u09C7\u09AF\u09BC", ms: "Celakalah orang-orang yang curang dalam sukatan" },
