        correctVerseMeaningTranslations: { en: "Indeed, the record of the wicked is in Sijjeen", ar: "\u0625\u0646 \u0643\u062A\u0627\u0628 \u0627\u0644\u0641\u062C\u0627\u0631 \u0644\u0641\u064A \u0633\u062C\u064A\u0646", id: "Sesungguhnya catatan orang-orang fasik ada dalam Sijjin", tr: "G\xFCnahk\xE2rlar\u0131n kayd\u0131 Seccinde'dir", zh: "\u90AA\u6076\u8005\u7684\u8BB0\u5F55\u786E\u5728\u897F\u91D1\u4E2D", sw: "Hakika kumbukumbu ya waovu iko Sijjin", so: "Xaqiiqdu kitaabkii fujaarada wuxuu ku jiraa Sijjiin", bs: "Zaista, knjiga grje\u0161nika je u Si\u010Dinu", sq: "Me t\xEB v\xEBrtet\xEB, regjistri i ne\u010Destiv\xEBve \xEBsht\xEB n\xEB Sixin", ru: "\u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u043A\u043D\u0438\u0433\u0430 \u0433\u0440\u0435\u0448\u043D\u0438\u043A\u043E\u0432 \u0432 \u0421\u0438\u0434\u0436\u0436\u0438\u043D\u0435", ur: "\u0628\u06D2 \u0634\u06A9 \u0641\u0627\u062C\u0631\u0648\u06BA \u06A9\u06CC \u06A9\u062A\u0627\u0628 \u0633\u062C\u06CC\u0646 \u0645\u06CC\u06BA \u06C1\u06D2", bn: "\u09A8\u09BF\u09B6\u09CD\u099A\u09AF\u09BC\u0987 \u09AA\u09BE\u09AA\u09C0\u09A6\u09C7\u09B0 \u0986\u09AE\u09B2\u09A8\u09BE\u09AE\u09BE \u09B8\u09BF\u099C\u09CD\u099C\u09BF\u09A8\u09C7 \u0986\u099B\u09C7", ms: "Sesungguhnya catatan orang-orang jahat ada dalam Sijjin" },
