        correctVerse: "\u0625\u0650\u0646\u064E\u0651 \u0643\u0650\u062A\u064E\u0627\u0628\u064E \u0627\u0644\u0652\u0641\u064F\u062C\u064E\u0651\u0627\u0631\u0650 \u0644\u064E\u0641\u0650\u064A \u0633\u0650\u062C\u0650\u0651\u064A\u0646\u064D",
