        targetWordTranslations: { en: "The Highest Place (Paradise's Record)", ar: "\u0623\u0639\u0644\u0649 \u0645\u0643\u0627\u0646 \u0641\u064A \u0627\u0644\u062C\u0646\u0629 \u2014 \u0633\u062C\u0644 \u0623\u0647\u0644 \u0627\u0644\u062C\u0646\u0629", id: "Tempat tertinggi (catatan ahli surga)", tr: "En y\xFCksek yer (cennetliklerin kayd\u0131)", zh: "\u6700\u9AD8\u4E4B\u5730\uFF08\u5929\u5802\u6863\u6848\uFF09", sw: "Mahali pa juu zaidi (kumbukumbu ya peponi)", so: "Meeshii ugu sarreysay (diiwaanka Jannada)", bs: "Najvi\u0161e mjesto (knjiga stanovnika d\u017Eenneta)", sq: "Vendi m\xEB i lart\xEB (regjistri i banor\xEBve t\xEB Xhenetit)", ru: "\u0412\u044B\u0441\u043E\u0447\u0430\u0439\u0448\u0435\u0435 \u043C\u0435\u0441\u0442\u043E (\u043A\u043D\u0438\u0433\u0430 \u043E\u0431\u0438\u0442\u0430\u0442\u0435\u043B\u0435\u0439 \u0440\u0430\u044F)", ur: "\u0633\u0628 \u0633\u06D2 \u0628\u0644\u0646\u062F \u062C\u06AF\u06C1 (\u062C\u0646\u062A\u06CC\u0648\u06BA \u06A9\u0627 \u0633\u062C\u0644)", bn: "\u09B8\u09B0\u09CD\u09AC\u09CB\u099A\u09CD\u099A \u09B8\u09CD\u09A5\u09BE\u09A8 (\u099C\u09BE\u09A8\u09CD\u09A8\u09BE\u09A4\u09AC\u09BE\u09B8\u09C0\u09A6\u09C7\u09B0 \u0986\u09AE\u09B2\u09A8\u09BE\u09AE\u09BE)", ms: "Tempat paling tinggi (catatan ahli syurga)" },
        correctVerseMeaningTranslations: { en: "Indeed, the record of the righteous is in Illiyyeen", ar: "\u0625\u0646 \u0643\u062A\u0627\u0628 \u0627\u0644\u0623\u0628\u0631\u0627\u0631 \u0644\u0641\u064A \u0639\u0644\u064A\u064A\u0646", id: "Sesungguhnya catatan orang-orang yang baik ada dalam Illiyyin", tr: "\u0130yilerin kayd\u0131 Illiyyunde'dir", zh: "\u5584\u826F\u8005\u7684\u8BB0\u5F55\u786E\u5728\u4F0A\u5229\u56E0\u4E2D", sw: "Hakika kumbukumbu ya wema iko Iliyyiyna", so: "Xaqiiqdu kitaabkii abaaradda wuxuu ku jiraa Cilliyyiin", bs: "Zaista, knjiga pravednika je u Illiyunu", sq: "Me t\xEB v\xEBrtet\xEB, regjistri i t\xEB mir\xEBve \xEBsht\xEB n\xEB Illijjin", ru: "\u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u043A\u043D\u0438\u0433\u0430 \u043F\u0440\u0430\u0432\u0435\u0434\u043D\u0438\u043A\u043E\u0432 \u0432 \u0418\u043B\u043B\u0438\u0439\u0439\u0438\u043D\u0435", ur: "\u0628\u06D2 \u0634\u06A9 \u0646\u06CC\u06A9\u0648\u06BA \u06A9\u06CC \u06A9\u062A\u0627\u0628 \u0639\u0644\u06CC\u06CC\u0646 \u0645\u06CC\u06BA \u06C1\u06D2", bn: "\u09A8\u09BF\u09B6\u09CD\u099A\u09AF\u09BC\u0987 \u09B8\u09CE\u0995\u09B0\u09CD\u09AE\u09B6\u09C0\u09B2\u09A6\u09C7\u09B0 \u0986\u09AE\u09B2\u09A8\u09BE\u09AE\u09BE \u0987\u09B2\u09CD\u09B2\u09BF\u09AF\u09BC\u09CD\u09AF\u09BF\u09A8\u09C7 \u0986\u099B\u09C7", ms: "Sesungguhnya catatan orang-orang yang baik ada dalam Illiyyin" },
        surahAyah: "\u0627\u0644\u0645\u0637\u0641\u0641\u064A\u0646:18",
        ayahNumber: 18,
        hint: "\u0627\u0644\u0645\u0642\u0627\u0628\u0644 \u0644\u0640\xAB\u0633\u062C\u064A\u0646\xBB \u2014 \u0623\u0639\u0644\u0649 \u0639\u0644\u0648\u0651 \u0644\u0623\u0647\u0644 \u0627\u0644\u062C\u0646\u0629",
        correctVerse: "\u0625\u0650\u0646\u064E\u0651 \u0643\u0650\u062A\u064E\u0627\u0628\u064E \u0627\u0644\u0623\u064E\u0628\u0652\u0631\u064E\u0627\u0631\u0650 \u0644\u064E\u0641\u0650\u064A \u0639\u0650\u0644\u0650\u0651\u064A\u0650\u0651\u064A\u0646\u064E",
