        correctVerseMeaningTranslations: { en: "O mankind, indeed you are laboring toward your Lord with great exertion", ar: "\u064A\u0627 \u0623\u064A\u0647\u0627 \u0627\u0644\u0625\u0646\u0633\u0627\u0646 \u0625\u0646\u0643 \u0643\u0627\u062F\u062D \u0625\u0644\u0649 \u0631\u0628\u0643 \u0643\u062F\u062D\u0627\u064B", id: "Wahai manusia, sesungguhnya kamu bersungguh-sungguh menuju Tuhanmu", tr: "Ey insan, sen Rabbine varmak i\xE7in durmadan \xE7abal\u0131yorsun", zh: "\u4EBA\u554A\uFF0C\u4F60\u786E\u5B9E\u5728\u52AA\u529B\u5730\u5954\u5411\u4F60\u7684\u4E3B", sw: "Ewe mtu, hakika unajitahidi kwenda kwa Mola wako", so: "Oo Aadanaha, xaqiiqdu waxaad u hawlgashaa Rabbigaa", bs: "O \u010Dovje\u010De, ti zaista naporno pati\u0161 ka svome Gospodaru", sq: "O njeri, ti me t\xEB v\xEBrtet\xEB mundohesh shum\xEB drejt Zotit t\xEBnd", ru: "\u041E \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u0442\u044B \u0443\u0441\u0435\u0440\u0434\u043D\u043E \u0441\u0442\u0440\u0435\u043C\u0438\u0448\u044C\u0441\u044F \u043A \u0441\u0432\u043E\u0435\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0443", ur: "\u0627\u06D2 \u0627\u0646\u0633\u0627\u0646 \u062A\u0648 \u0627\u067E\u0646\u06D2 \u0631\u0628 \u06A9\u06CC \u0637\u0631\u0641 \u0633\u062E\u062A \u06A9\u0648\u0634\u0634 \u06A9\u0631\u062A\u0627 \u06C1\u06D2", bn: "\u09B9\u09C7 \u09AE\u09BE\u09A8\u09C1\u09B7! \u09A4\u09C1\u09AE\u09BF \u09A4\u09CB\u09AE\u09BE\u09B0 \u09B0\u09AC\u09C7\u09B0 \u09A6\u09BF\u0995\u09C7 \u0995\u09A0\u09CB\u09B0 \u09AA\u09B0\u09BF\u09B6\u09CD\u09B0\u09AE \u0995\u09B0\u099B", ms: "Wahai manusia, sesungguhnya kamu bersungguh-sungguh menuju Tuhanmu" },
