        correctVerse: "\u0625\u0650\u0646\u064E\u0651\u0643\u064E \u0643\u064E\u0627\u062F\u0650\u062D\u064C \u0625\u0650\u0644\u064E\u0649 \u0631\u064E\u0628\u0650\u0651\u0643\u064E \u0643\u064E\u062F\u0652\u062D\u064B\u0627",
