        targetWordTranslations: { en: "The Most High", ar: "\u0627\u0644\u0623\u0631\u0641\u0639 \u0627\u0644\u0623\u0633\u0645\u0649", id: "Yang Maha Tinggi", tr: "En Y\xFCce", zh: "\u81F3\u9AD8\u8005", sw: "Aliye Juu Zaidi", so: "Ugu Sarreeya", bs: "Uzvi\u0161eni", sq: "Shum\xEB i Larti", ru: "\u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0438\u0439", ur: "\u0633\u0628 \u0633\u06D2 \u0628\u0644\u0646\u062F", bn: "\u09B8\u09B0\u09CD\u09AC\u09CB\u099A\u09CD\u099A", ms: "Yang Maha Tinggi" },
        correctVerseMeaningTranslations: { en: "Glorify the name of your Lord, the Most High", ar: "\u0633\u0628\u0651\u062D \u0627\u0633\u0645 \u0631\u0628\u0643 \u0627\u0644\u0623\u0639\u0644\u0649", id: "Sucikanlah nama Tuhanmu yang Maha Tinggi", tr: "Y\xFCce Rabbinin ad\u0131n\u0131 tesbih et", zh: "\u4F60\u5F53\u8D5E\u7F8E\u4F60\u81F3\u9AD8\u4E4B\u4E3B\u7684\u540D", sw: "Tukuza jina la Mola wako Mtukufu", so: "U Sabbaaxo magaca Rabbigaa ugu Sarreeya", bs: "Slavi ime svoga Gospodara, Uzvi\u0161enog", sq: "Lart\xEBso emrin e Zotit t\xEBnd, Shum\xEB t\xEB Lartit", ru: "\u041F\u0440\u043E\u0441\u043B\u0430\u0432\u043B\u044F\u0439 \u0438\u043C\u044F \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0422\u0432\u043E\u0435\u0433\u043E \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0435\u0433\u043E", ur: "\u0627\u067E\u0646\u06D2 \u0631\u0628 \u0627\u0639\u0644\u06CC\u0670 \u06A9\u06D2 \u0646\u0627\u0645 \u06A9\u06CC \u062A\u0633\u0628\u06CC\u062D \u06A9\u0631\u0648", bn: "\u09A4\u09CB\u09AE\u09BE\u09B0 \u09AE\u09B9\u09BE\u09A8 \u09B0\u09AC\u09C7\u09B0 \u09A8\u09BE\u09AE \u09AA\u09AC\u09BF\u09A4\u09CD\u09B0 \u0998\u09CB\u09B7\u09A3\u09BE \u0995\u09B0", ms: "Bertasbihlah dengan nama Tuhanmu Yang Maha Tinggi" },
        surahAyah: "\u0627\u0644\u0623\u0639\u0644\u0649:1",
