        correctVerse: "\u0633\u064E\u0628\u0650\u0651\u062D\u0650 \u0627\u0633\u0652\u0645\u064E \u0631\u064E\u0628\u0650\u0651\u0643\u064E \u0627\u0644\u0623\u064E\u0639\u0652\u0644\u064E\u0649",
