        targetWordTranslations: { en: "Will Be Reminded / Remember", ar: "\u0633\u064A\u062A\u0630\u0643\u0631 \u0648\u064A\u062A\u0651\u0639\u0638", id: "Akan mengingat / mendapat peringatan", tr: "Hat\u0131rlayacak / \xD6\u011F\xFCt alacak", zh: "\u4F1A\u94ED\u8BB0/\u9886\u609F", sw: "Atakapokumbuka", so: "Ka xasuusanaya", bs: "Podsjetit \u0107e se", sq: "Do t\xEB kujtoj\xEB", ru: "\u0417\u0430\u043F\u043E\u043C\u043D\u0438\u0442 / \u0412\u0441\u043F\u043E\u043C\u043D\u0438\u0442", ur: "\u06CC\u0627\u062F \u06A9\u0631\u06D2 \u06AF\u0627 / \u0639\u0628\u0631\u062A \u0644\u06D2 \u06AF\u0627", bn: "\u09B8\u09CD\u09AE\u09B0\u09A3 \u0995\u09B0\u09AC\u09C7", ms: "Akan mengingati" },
        correctVerseMeaningTranslations: { en: "The reminder will benefit whoever fears Allah", ar: "\u0633\u064A\u0630\u0651\u0643\u0631 \u0645\u0646 \u064A\u062E\u0634\u0649", id: "Orang yang takut kepada Allah akan mengambil pelajaran", tr: "Allah'tan korkan \xF6\u011F\xFCt al\u0131r", zh: "\u6709\u6240\u656C\u754F\u8005\u4F1A\u4ECE\u4E2D\u5F97\u76CA", sw: "Atakapokumbuka anayemcha Allah", so: "Kun baqayaa baa xasuusanaya", bs: "Ko se boji Allaha, podsjetit \u0107e se", sq: "Do t\xEB kujtoj\xEB ai q\xEB frik\xEBsohet prej Allahut", ru: "\u041D\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u043F\u0440\u0438\u043D\u0435\u0441\u0451\u0442 \u043F\u043E\u043B\u044C\u0437\u0443 \u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u0431\u043E\u0438\u0442\u0441\u044F", ur: "\u062C\u0648 \u0688\u0631\u06D2 \u06AF\u0627 \u0648\u06C1 \u0646\u0635\u06CC\u062D\u062A \u067E\u06A9\u0691\u06D2 \u06AF\u0627", bn: "\u09AF\u09C7 \u09AD\u09AF\u09BC \u0995\u09B0\u09C7 \u09B8\u09C7 \u09B8\u09CD\u09AE\u09B0\u09A3 \u0995\u09B0\u09AC\u09C7", ms: "Dia akan mengingat siapa yang takutkan Allah" },
