        correctVerseMeaningTranslations: { en: "Has there come to you the report of the Overwhelming Event", ar: "\u0647\u0644 \u0623\u062A\u0627\u0643 \u062D\u062F\u064A\u062B \u0627\u0644\u063A\u0627\u0634\u064A\u0629", id: "Sudahkah datang kepadamu berita tentang Hari Kiamat", tr: "Sana her \u015Feyi kaplayan g\xFCn\xFCn haberi geldi mi", zh: "\u4F60\u542C\u8BF4\u90A3\u7B3C\u7F69\u4E00\u5207\u7684\u5927\u4E8B\u4E86\u5417", sw: "Je, imekujia habari ya Tukio Kubwa", so: "Miyaadan maqlin Wariyaha Gaaditaanka", bs: "Zar ti nije stigla vijest o Sudnjem danu", sq: "A t\xEB erdhi lajmi i Ngjarjes mbizot\xEBruese", ru: "\u0420\u0430\u0437\u0432\u0435 \u043D\u0435 \u0434\u043E\u0448\u0451\u043B \u0434\u043E \u0442\u0435\u0431\u044F \u0440\u0430\u0441\u0441\u043A\u0430\u0437 \u043E \u0412\u0441\u0435\u043F\u043E\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0435\u043C", ur: "\u06A9\u06CC\u0627 \u062A\u0645\u06C1\u0627\u0631\u06D2 \u067E\u0627\u0633 \u0688\u06BE\u0627\u0646\u067E \u0644\u06CC\u0646\u06D2 \u0648\u0627\u0644\u06D2 \u06A9\u06CC \u062E\u0628\u0631 \u0622\u0626\u06CC", bn: "\u09A4\u09CB\u09AE\u09BE\u09B0 \u0995\u09BE\u099B\u09C7 \u0995\u09BF \u09B8\u09B0\u09CD\u09AC\u0997\u09CD\u09B0\u09BE\u09B8\u09C0 \u0998\u099F\u09A8\u09BE\u09B0 \u09B8\u0982\u09AC\u09BE\u09A6 \u098F\u09B8\u09C7\u099B\u09C7", ms: "Sudahkah datang kepadamu berita tentang Peristiwa yang Menyelubungi" },
        surahAyah: "\u0627\u0644\u063A\u0627\u0634\u064A\u0629:1",
        ayahNumber: 1,
        hint: "\u0627\u0633\u0645 \u0644\u064A\u0648\u0645 \u0627\u0644\u0642\u064A\u0627\u0645\u0629 \u0644\u0623\u0646\u0647 \u064A\u063A\u0634\u0649 \u0627\u0644\u0646\u0627\u0633 \u0628\u0623\u0647\u0648\u0627\u0644\u0647",
        correctVerse: "\u0647\u064E\u0644\u0652 \u0623\u064E\u062A\u064E\u0627\u0643\u064E \u062D\u064E\u062F\u0650\u064A\u062B\u064F \u0627\u0644\u0652\u063A\u064E\u0627\u0634\u0650\u064A\u064E\u0629\u0650",
        correctVerseMeaning: "Has there come to you the report of the Overwhelming Event",
        options: [{ text: "\u0627\u0644\u0652\u063A\u064E\u0627\u0634\u0650\u064A\u064E\u0629\u064F", isCorrect: true }, { text: "\u0627\u0644\u0637\u064E\u0651\u0627\u0645\u064E\u0651\u0629\u064F", isCorrect: false }, { text: "\u0627\u0644\u0652\u0642\u064E\u0627\u0631\u0650\u0639\u064E\u0629\u064F", isCorrect: false }, { text: "\u0627\u0644\u0632\u064E\u0651\u0644\u0652\u0632\u064E\u0644\u064E\u0629\u064F", isCorrect: false }]
