        correctVerseMeaningTranslations: { en: "By the night when it covers", ar: "\u0648\u0627\u0644\u0644\u064A\u0644 \u0625\u0630\u0627 \u064A\u063A\u0634\u0649", id: "Demi malam apabila menutupi", tr: "\xD6rtt\xFC\u011F\xFCnde geceye yemin olsun", zh: "\u4EE5\u591C\u5E55\u8986\u76D6\u65F6\u4E3A\u8A93", sw: "Naapa kwa usiku unapoufunika", so: "Habeenka uu dabooli markuu", bs: "Tako mi no\u0107i kada pokrije", sq: "Betohem n\xEB nat\xEBn kur mbulon", ru: "\u041A\u043B\u044F\u043D\u0443\u0441\u044C \u043D\u043E\u0447\u044C\u044E, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u0442", ur: "\u0642\u0633\u0645 \u06C1\u06D2 \u0631\u0627\u062A \u06A9\u06CC \u062C\u0628 \u0688\u06BE\u0627\u0646\u067E \u0644\u06D2", bn: "\u09B0\u09BE\u09A4\u09C7\u09B0 \u09B6\u09AA\u09A5 \u09AF\u0996\u09A8 \u09B8\u09C7 \u0986\u099A\u09CD\u099B\u09BE\u09A6\u09BF\u09A4 \u0995\u09B0\u09C7", ms: "Demi malam apabila menutupi" },
