        targetWordTranslations: { en: "By the Pen", ar: "\u0628\u0648\u0627\u0633\u0637\u0629 \u0627\u0644\u0642\u0644\u0645", id: "Dengan pena", tr: "Kalemle", zh: "\u4EE5\u7B14", sw: "Kwa kalamu", so: "Qalinku", bs: "Perom", sq: "Me pend\xEB", ru: "\u041F\u0435\u0440\u043E\u043C / \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u0430\u043B\u0430\u043C\u0430", ur: "\u0642\u0644\u0645 \u0633\u06D2", bn: "\u0995\u09B2\u09AE \u09A6\u09BF\u09AF\u09BC\u09C7", ms: "Dengan pena" },
        correctVerseMeaningTranslations: { en: "Who taught by the pen", ar: "\u0627\u0644\u0630\u064A \u0639\u0644\u0651\u0645 \u0628\u0627\u0644\u0642\u0644\u0645", id: "Yang mengajar manusia dengan perantaraan pena", tr: "\u0130nsana kalemle \xF6\u011Fretti", zh: "\u4EE5\u7B14\u6559\u5BFC\u4EBA", sw: "Aliyefundisha kwa kalamu", so: "Qalinku buu baray", bs: "Koji je perom podu\u010Davao", sq: "Ai q\xEB m\xEBsoi me pend\xEB", ru: "\u041A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0430\u0443\u0447\u0438\u043B \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u0430\u043B\u0430\u043C\u0430", ur: "\u062C\u0633 \u0646\u06D2 \u0642\u0644\u0645 \u06A9\u06D2 \u0630\u0631\u06CC\u0639\u06D2 \u0639\u0644\u0645 \u062F\u06CC\u0627", bn: "\u09AF\u09BF\u09A8\u09BF \u0995\u09B2\u09AE \u09A6\u09BF\u09AF\u09BC\u09C7 \u09B6\u09BF\u0995\u09CD\u09B7\u09BE \u09A6\u09BF\u09AF\u09BC\u09C7\u099B\u09C7\u09A8", ms: "Yang mengajar manusia dengan pena" },
        surahAyah: "\u0627\u0644\u0639\u0644\u0642:4",
