        correctVerse: "\u0627\u0644\u064E\u0651\u0630\u0650\u064A \u0639\u064E\u0644\u064E\u0651\u0645\u064E \u0628\u0650\u0627\u0644\u0652\u0642\u064E\u0644\u064E\u0645\u0650",
