        targetWordTranslations: { en: "The Spirit (Angel Jibreel)", ar: "\u062C\u0628\u0631\u064A\u0644 \u0639\u0644\u064A\u0647 \u0627\u0644\u0633\u0644\u0627\u0645", id: "Ruh (Jibril)", tr: "Ruh (Cebrail)", zh: "\u5723\u7075\uFF08\u5929\u4F7F\u5409\u5E03\u91CC\u52D2\uFF09", sw: "Roho (Jibril)", so: "Ruuxa (Jibriil)", bs: "Duh (D\u017Eibril)", sq: "Shpirti (Xhibrili)", ru: "\u0414\u0443\u0445 (\u0430\u043D\u0433\u0435\u043B \u0414\u0436\u0438\u0431\u0440\u0438\u043B\u044C)", ur: "\u0631\u0648\u062D \u0627\u0644\u0642\u062F\u0633 (\u062C\u0628\u0631\u06CC\u0644)", bn: "\u09B0\u09C1\u09B9 (\u099C\u09BF\u09AC\u09CD\u09B0\u09BE\u0987\u09B2)", ms: "Ruh (Jibril)" },
        correctVerseMeaningTranslations: { en: "The angels and the Spirit descend therein by permission of their Lord", ar: "\u062A\u0646\u0632\u0651\u0644 \u0627\u0644\u0645\u0644\u0627\u0626\u0643\u0629 \u0648\u0627\u0644\u0631\u0648\u062D \u0641\u064A\u0647\u0627 \u0628\u0625\u0630\u0646 \u0631\u0628\u0647\u0645", id: "Para malaikat dan Ruh turun di malam itu dengan izin Tuhan mereka", tr: "Melekler ve Ruh, Rabblerinin izniyle iner", zh: "\u5929\u4F7F\u548C\u5723\u7075\u5728\u90A3\u591C\u5949\u4ED6\u4EEC\u4E3B\u7684\u547D\u4EE4\u964D\u4E34", sw: "Malaika na Roho hushuka usiku huo kwa ruhusa ya Mola wao", so: "Malaa'igaha iyo Ruuxa bay ugu dhacaan habeenkaas", bs: "Meleci i D\u017Eibril spu\u0161taju se te no\u0107i po dozvoli svog Gospodara", sq: "Engj\xEBjt dhe Shpirti zbresin at\xEB nat\xEB me lejen e Zotit t\xEB tyre", ru: "\u0412 \u043D\u0435\u0451 \u043D\u0438\u0441\u0445\u043E\u0434\u044F\u0442 \u0430\u043D\u0433\u0435\u043B\u044B \u0438 \u0414\u0443\u0445 \u0441 \u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u0438\u044F \u0438\u0445 \u0413\u043E\u0441\u043F\u043E\u0434\u0430", ur: "\u0641\u0631\u0634\u062A\u06D2 \u0627\u0648\u0631 \u0631\u0648\u062D \u0627\u0633 \u0645\u06CC\u06BA \u0627\u067E\u0646\u06D2 \u0631\u0628 \u06A9\u06CC \u0627\u062C\u0627\u0632\u062A \u0633\u06D2 \u0627\u062A\u0631\u062A\u06D2 \u06C1\u06CC\u06BA", bn: "\u09A4\u09BE\u09A4\u09C7 \u09AB\u09C7\u09B0\u09C7\u09B6\u09A4\u09BE \u0993 \u09B0\u09C2\u09B9 \u09A4\u09BE\u09A6\u09C7\u09B0 \u09B0\u09AC\u09C7\u09B0 \u0985\u09A8\u09C1\u09AE\u09A4\u09BF\u0995\u09CD\u09B0\u09AE\u09C7 \u0985\u09AC\u09A4\u09C0\u09B0\u09CD\u09A3 \u09B9\u09AF\u09BC", ms: "Para malaikat dan Ruh turun padanya dengan izin Tuhan mereka" },
        surahAyah: "\u0627\u0644\u0642\u062F\u0631:4",
        ayahNumber: 4,
        hint: "\u062C\u0628\u0631\u064A\u0644 \u0639\u0644\u064A\u0647 \u0627\u0644\u0633\u0644\u0627\u0645 \u2014 \u064A\u064F\u0633\u0645\u0651\u0649 \u0628\u0627\u0644\u0631\u0648\u062D",
        correctVerse: "\u062A\u064E\u0646\u064E\u0632\u064E\u0651\u0644\u064F \u0627\u0644\u0652\u0645\u064E\u0644\u0627\u0626\u0650\u0643\u064E\u0629\u064F \u0648\u064E\u0627\u0644\u0631\u064F\u0651\u0648\u062D\u064F \u0641\u0650\u064A\u0647\u064E\u0627",
        correctVerseMeaning: "The angels and the Spirit descend therein",
        options: [{ text: "\u0627\u0644\u0631\u064F\u0651\u0648\u062D\u064F", isCorrect: true }, { text: "\u0627\u0644\u0652\u0645\u064E\u0644\u0627\u0626\u0650\u0643\u064E\u0629\u064F", isCorrect: false }, { text: "\u0627\u0644\u0652\u0642\u064E\u062F\u0652\u0631\u064F", isCorrect: false }, { text: "\u0627\u0644\u0633\u064E\u0651\u0644\u0627\u0645\u064F", isCorrect: false }]
