        targetWordMeaning: "The Clear Proof / Evidence",
        targetWordTranslations: { en: "The Clear Proof / Evidence", ar: "\u0627\u0644\u062F\u0644\u064A\u0644 \u0627\u0644\u0648\u0627\u0636\u062D \u0627\u0644\u0628\u064A\u0651\u0646", id: "Bukti nyata", tr: "A\xE7\u0131k delil / Kan\u0131t", zh: "\u660E\u786E\u7684\u8BC1\u660E", sw: "Ushahidi Wazi", so: "Caddaynta Cad", bs: "Jasni dokaz", sq: "D\xEBshmi e qart\xEB", ru: "\u042F\u0441\u043D\u043E\u0435 \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E", ur: "\u0648\u0627\u0636\u062D \u062F\u0644\u06CC\u0644", bn: "\u09B8\u09CD\u09AA\u09B7\u09CD\u099F \u09AA\u09CD\u09B0\u09AE\u09BE\u09A3", ms: "Bukti yang nyata" },
        correctVerseMeaningTranslations: { en: "Those who disbelieved were not to be separated until the clear proof came to them", ar: "\u0644\u0645 \u064A\u0643\u0646 \u0627\u0644\u0630\u064A\u0646 \u0643\u0641\u0631\u0648\u0627 \u0645\u0646\u0641\u0643\u064A\u0646 \u062D\u062A\u0649 \u062A\u0623\u062A\u064A\u0647\u0645 \u0627\u0644\u0628\u064A\u0646\u0629", id: "Orang-orang kafir tidak akan meninggalkan kekafirannya sampai datang kepada mereka bukti yang nyata", tr: "K\xE2firler, kendilerine a\xE7\u0131k delil gelinceye kadar k\xFCf\xFCrden ayr\u0131lacak de\u011Fillerdi", zh: "\u4E0D\u4FE1\u9053\u8005\u5728\u83B7\u5F97\u660E\u786E\u8BC1\u660E\u4E4B\u524D\u662F\u4E0D\u4F1A\u653E\u5F03\u7684", sw: "Wale waliokufuru hawakuwa watatengana mpaka ushahidi wazi uwafikie", so: "Kuwa Gaaloobay uma bixin lahayn xaaladdooda illaa Bayinadda la gaadho", bs: "Nevjernici se nisu namjeravali odre\u0107i svog nevjerstva dok im ne do\u0111e jasni dokaz", sq: "Jobesimtar\xEBt nuk do t\xEB linin mosbesimin derisa t\xEB vinte prova e qart\xEB", ru: "\u0422\u0435, \u043A\u0442\u043E \u043D\u0435 \u0443\u0432\u0435\u0440\u043E\u0432\u0430\u043B\u0438, \u043D\u0435 \u043E\u0442\u0441\u0442\u0443\u043F\u0438\u043B\u0438\u0441\u044C \u0431\u044B, \u043F\u043E\u043A\u0430 \u043D\u0435 \u043F\u0440\u0438\u0448\u043B\u043E \u043A \u043D\u0438\u043C \u044F\u0441\u043D\u043E\u0435 \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E", ur: "\u06A9\u0627\u0641\u0631 \u0627\u0644\u06AF \u0646\u06C1\u06CC\u06BA \u06C1\u0648\u062A\u06D2 \u062A\u06BE\u06D2 \u062C\u0628 \u062A\u06A9 \u0627\u0646 \u06A9\u06D2 \u067E\u0627\u0633 \u0628\u06CC\u0651\u0646\u06C1 \u0646\u06C1 \u0622 \u062C\u0627\u0626\u06D2", bn: "\u0995\u09BE\u09AB\u09BF\u09B0\u09B0\u09BE \u09AC\u09BF\u09B0\u09A4 \u09B9\u09AC\u09C7 \u09A8\u09BE \u09AF\u09A4\u0995\u09CD\u09B7\u09A3 \u09A4\u09BE\u09A6\u09C7\u09B0 \u0995\u09BE\u099B\u09C7 \u09B8\u09CD\u09AA\u09B7\u09CD\u099F \u09AA\u09CD\u09B0\u09AE\u09BE\u09A3 \u09A8\u09BE \u0986\u09B8\u09C7", ms: "Orang-orang kafir tidak akan meninggalkan kesesatannya sehingga datang kepada mereka bukti yang nyata" },
        surahAyah: "\u0627\u0644\u0628\u064A\u0651\u0646\u0629:1",
        ayahNumber: 1,
        hint: "\u0627\u0644\u062D\u062C\u0629 \u0627\u0644\u0648\u0627\u0636\u062D\u0629 \u0627\u0644\u062A\u064A \u0644\u0627 \u062A\u0642\u0628\u0644 \u0627\u0644\u0634\u0643",
        correctVerse: "\u062D\u064E\u062A\u064E\u0651\u0649 \u062A\u064E\u0623\u0652\u062A\u0650\u064A\u064E\u0647\u064F\u0645\u064F \u0627\u0644\u0652\u0628\u064E\u064A\u0650\u0651\u0646\u064E\u0629\u064F",
        correctVerseMeaning: "Until the clear proof came to them",
