        correctVerseMeaningTranslations: { en: "When the earth is shaken with its quake", ar: "\u0625\u0630\u0627 \u0632\u0644\u0632\u0644\u062A \u0627\u0644\u0623\u0631\u0636 \u0632\u0644\u0632\u0627\u0644\u0647\u0627", id: "Apabila bumi diguncang dengan guncangan yang dahsyat", tr: "Yer \u015Fiddetle sars\u0131ld\u0131\u011F\u0131nda", zh: "\u5F53\u5927\u5730\u9707\u52A8\u5267\u70C8\u65F6", sw: "Ardhi inapotikiswa kwa kutikisika kwake", so: "Dhulkii garir ku gariirtay", bs: "Kada se zemlja zatrese sna\u017Enim potresom", sq: "Kur toka t\xEB tronditej me tronditjen e saj", ru: "\u041A\u043E\u0433\u0434\u0430 \u0437\u0435\u043C\u043B\u044F \u0441\u043E\u0442\u0440\u044F\u0441\u0451\u0442\u0441\u044F \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0442\u0440\u044F\u0441\u0435\u043D\u0438\u0435\u043C", ur: "\u062C\u0628 \u0632\u0645\u06CC\u0646 \u0627\u067E\u0646\u06CC \u0632\u0644\u0632\u0644\u06D2 \u0633\u06D2 \u06C1\u0644\u0627\u0626\u06CC \u062C\u0627\u0626\u06D2 \u06AF\u06CC", bn: "\u09AF\u0996\u09A8 \u09AD\u09C2\u09AE\u09BF \u09A4\u09BE\u09B0 \u09AD\u09C0\u09B7\u09A3 \u0995\u09AE\u09CD\u09AA\u09A8\u09C7 \u0995\u09BE\u0981\u09AA\u09AC\u09C7", ms: "Apabila bumi digegarkan dengan gegaran yang dahsyat" },
