        correctVerse: "\u0625\u0650\u0630\u064E\u0627 \u0632\u064F\u0644\u0652\u0632\u0650\u0644\u064E\u062A\u0650 \u0627\u0644\u0623\u064E\u0631\u0652\u0636\u064F \u0632\u0650\u0644\u0652\u0632\u064E\u0627\u0644\u064E\u0647\u064E\u0627",
