        targetWordTranslations: { en: "Those Who Run (War Horses)", ar: "\u0627\u0644\u062E\u064A\u0644 \u0627\u0644\u0645\u0633\u0631\u0639\u0629 \u0641\u064A \u0627\u0644\u062C\u0631\u064A", id: "Kuda yang berlari kencang", tr: "Ko\u015Fan atlar", zh: "\u5954\u9A70\u7684\u6218\u9A6C", sw: "Farasi wanaokimbia", so: "Farasaha Ordayo", bs: "Konji koji jure", sq: "Kuajt q\xEB vrapojn\xEB", ru: "\u041C\u0447\u0430\u0449\u0438\u0435\u0441\u044F (\u0431\u043E\u0435\u0432\u044B\u0435 \u043A\u043E\u043D\u0438)", ur: "\u062A\u06CC\u0632 \u062F\u0648\u0691\u0646\u06D2 \u0648\u0627\u0644\u06D2 (\u06AF\u06BE\u0648\u0691\u06D2)", bn: "\u09A6\u09CC\u09A1\u09BC\u09BE\u09A8\u09CB \u0998\u09CB\u09A1\u09BC\u09BE", ms: "Kuda-kuda yang berlari kencang" },
        correctVerseMeaningTranslations: { en: "By the racers panting", ar: "\u0648\u0627\u0644\u0639\u0627\u062F\u064A\u0627\u062A \u0636\u0628\u062D\u0627\u064B", id: "Demi kuda yang berlari kencang sambil terengah-engah", tr: "Soluyarak ko\u015Fan atlara yemin olsun", zh: "\u4EE5\u6C14\u5598\u5401\u5401\u5954\u9A70\u7684\u6218\u9A6C\u4E3A\u8A93", sw: "Naapa kwa farasi wanaokimbia kwa kupumua kwa nguvu", so: "Farasaha Ordaya ee xaariso duwaysha", bs: "Tako mi konja koji jure hr\u010Du\u0107i", sq: "Betohem n\xEB ata q\xEB vrapojn\xEB duke nxjerr\xEB frym\xEB", ru: "\u041A\u043B\u044F\u043D\u0443\u0441\u044C \u043C\u0447\u0430\u0449\u0438\u043C\u0438\u0441\u044F \u0437\u0430\u043F\u044B\u0445\u0430\u0432\u0448\u0438\u043C\u0438\u0441\u044F", ur: "\u0642\u0633\u0645 \u06C1\u06D2 \u06C1\u0627\u0646\u067E\u062A\u06D2 \u06C1\u0648\u0626\u06D2 \u062F\u0648\u0691\u0646\u06D2 \u0648\u0627\u0644\u0648\u06BA (\u06AF\u06BE\u0648\u0691\u0648\u06BA) \u06A9\u06CC", bn: "\u09B9\u09BE\u0981\u09AA\u09BE\u09A4\u09C7 \u09B9\u09BE\u0981\u09AA\u09BE\u09A4\u09C7 \u09A6\u09CC\u09A1\u09BC\u09BE\u09A8\u09CB\u09B0 \u09B6\u09AA\u09A5", ms: "Demi kuda-kuda yang berlari kencang sambil terengah-engah" },
