        correctVerse: "\u0648\u064E\u0627\u0644\u0652\u0639\u064E\u0627\u062F\u0650\u064A\u064E\u0627\u062A\u0650 \u0636\u064E\u0628\u0652\u062D\u064B\u0627",
        correctVerseMeaning: "By the racers panting",
