        targetWordMeaning: "The Striking Hour (Calamity)",
        targetWordTranslations: { en: "The Striking Hour (Calamity)", ar: "\u0627\u0644\u0637\u0627\u0631\u0642\u0629 \u0627\u0644\u0645\u0642\u0631\u0639\u0629 \u2014 \u0627\u0644\u0642\u064A\u0627\u0645\u0629", id: "Hari Kiamat yang mengguncang", tr: "\xC7arpan Saat (K\u0131yamet)", zh: "\u731B\u51FB\u4E4B\u65E5/\u707E\u96BE", sw: "Tukio Linaloopiga", so: "Dhacdada Garaacaysa", bs: "Udaraju\u0107i dan (Sudnji)", sq: "Ngjarja Godit\xEBse (Kiyameti)", ru: "\u0421\u043E\u043A\u0440\u0443\u0448\u0430\u044E\u0449\u0438\u0439 \u0443\u0434\u0430\u0440 (\u0421\u0443\u0434\u043D\u044B\u0439 \u0434\u0435\u043D\u044C)", ur: "\u06A9\u06BE\u0679\u06A9\u06BE\u0679\u0627\u0646\u06D2 \u0648\u0627\u0644\u06CC (\u0642\u06CC\u0627\u0645\u062A)", bn: "\u0986\u0998\u09BE\u09A4\u0995\u09BE\u09B0\u09C0 \u0998\u099F\u09A8\u09BE (\u0995\u09BF\u09AF\u09BC\u09BE\u09AE\u09A4)", ms: "Bencana Dahsyat yang Melanda" },
        correctVerseMeaningTranslations: { en: "The Striking Calamity \u2014 what is the Striking Calamity?", ar: "\u0627\u0644\u0642\u0627\u0631\u0639\u0629 \u0645\u0627 \u0627\u0644\u0642\u0627\u0631\u0639\u0629", id: "Hari Kiamat, apa Hari Kiamat itu?", tr: "\xC7arpan k\u0131yamet! Nedir \xE7arpan k\u0131yamet?", zh: "\u5927\u707E\u96BE\uFF01\u4EC0\u4E48\u662F\u5927\u707E\u96BE\uFF1F", sw: "Tukio Linaloopiga \u2014 ni nini Tukio Linaloopiga?", so: "Qaari'adda \u2014 maxay Qaari'addu tahay?", bs: "Udaraju\u0107i dan \u2014 \u0161to je udaraju\u0107i dan?", sq: "Goditja \u2014 \xE7far\xEB \xEBsht\xEB Goditja?", ru: "\u0421\u043E\u043A\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u0443\u0434\u0430\u0440! \u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u0441\u043E\u043A\u0440\u0443\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u0443\u0434\u0430\u0440?", ur: "\u06A9\u06BE\u0679\u06A9\u06BE\u0679\u0627\u0646\u06D2 \u0648\u0627\u0644\u06CC \u2014 \u06A9\u06CC\u0627 \u06C1\u06D2 \u06A9\u06BE\u0679\u06A9\u06BE\u0679\u0627\u0646\u06D2 \u0648\u0627\u0644\u06CC\u061F", bn: "\u0986\u0998\u09BE\u09A4\u0995\u09BE\u09B0\u09C0 \u2014 \u0995\u09C0 \u09B8\u09C7\u0987 \u0986\u0998\u09BE\u09A4\u0995\u09BE\u09B0\u09C0?", ms: "Bencana yang melanda \u2014 apakah Bencana yang melanda itu?" },
