        targetWordTranslations: { en: "Those Who Are Patient", ar: "\u0627\u0644\u0645\u062A\u062D\u0645\u0644\u0648\u0646 \u0644\u0644\u0645\u0634\u0627\u0642 \u0628\u062B\u0628\u0627\u062A", id: "Orang-orang yang sabar", tr: "Sabredenler", zh: "\u6709\u8010\u5FC3\u7684\u4EBA", sw: "Wanaostahimili", so: "Kuwa Dulqaata", bs: "Strpljivi", sq: "Ata q\xEB jan\xEB t\xEB duruesh\xEBm", ru: "\u0422\u0435\u0440\u043F\u0435\u043B\u0438\u0432\u044B\u0435", ur: "\u0635\u0628\u0631 \u06A9\u0631\u0646\u06D2 \u0648\u0627\u0644\u06D2", bn: "\u09A7\u09C8\u09B0\u09CD\u09AF\u09B6\u09C0\u09B2\u09B0\u09BE", ms: "Orang-orang yang sabar" },
        correctVerseMeaningTranslations: { en: "And advising each other to patience", ar: "\u0648\u062A\u0648\u0627\u0635\u0648\u0627 \u0628\u0627\u0644\u0635\u0628\u0631", id: "Dan saling menasihati untuk kesabaran", tr: "Ve birbirine sabr\u0131 tavsiye edenler", zh: "\u5E76\u76F8\u4E92\u544A\u8BEB\u5FCD\u8010", sw: "Na kusahihishana katika uvumilivu", so: "Isu dardaarmaya Sabirka", bs: "I koji jedni drugima preporu\u010Duju strpljivost", sq: "Dhe q\xEB porosisin nj\xEBri-tjetrin me durim", ru: "\u0418 \u043A\u0442\u043E \u0437\u0430\u043F\u043E\u0432\u0435\u0434\u0443\u0435\u0442 \u0442\u0435\u0440\u043F\u0435\u043D\u0438\u0435", ur: "\u0627\u0648\u0631 \u0627\u06CC\u06A9 \u062F\u0648\u0633\u0631\u06D2 \u06A9\u0648 \u0635\u0628\u0631 \u06A9\u06CC \u0646\u0635\u06CC\u062D\u062A \u06A9\u0631\u0646\u06D2 \u0648\u0627\u0644\u06D2", bn: "\u098F\u09AC\u0982 \u09AA\u09B0\u09B8\u09CD\u09AA\u09B0\u0995\u09C7 \u09A7\u09C8\u09B0\u09CD\u09AF\u09C7\u09B0 \u0989\u09AA\u09A6\u09C7\u09B6 \u09A6\u09C7\u0993\u09AF\u09BC\u09BE", ms: "Dan saling berpesan dengan kesabaran" },
