        targetWordTranslations: { en: "The Slanderer / Mocker", ar: "\u0645\u0646 \u064A\u0639\u064A\u0628 \u0648\u064A\u0643\u0633\u0631 \u0642\u0644\u0648\u0628 \u0627\u0644\u0646\u0627\u0633", id: "Pencela / Penghina", tr: "\xC7eki\u015Ftirici / Alay edici", zh: "\u6BC1\u8C24\u8005/\u5632\u8BBD\u8005", sw: "Mtukutu / Mkejeli", so: "Kii Aflagaadeyn jiray", bs: "Klevetnik / Ruga\u010D", sq: "Grindavec / Tall\xEBs", ru: "\u0425\u0443\u043B\u0438\u0442\u0435\u043B\u044C / \u041D\u0430\u0441\u043C\u0435\u0448\u043D\u0438\u043A", ur: "\u0639\u06CC\u0628 \u0644\u06AF\u0627\u0646\u06D2 \u0648\u0627\u0644\u0627/\u0645\u0630\u0627\u0642 \u0627\u0691\u0627\u0646\u06D2 \u0648\u0627\u0644\u0627", bn: "\u09A8\u09BF\u09A8\u09CD\u09A6\u09C1\u0995/\u09AC\u09BF\u09A6\u09CD\u09B0\u09C2\u09AA\u0995\u09BE\u09B0\u09C0", ms: "Pencela / Penghina" },
        correctVerseMeaningTranslations: { en: "Woe to every scorner and mocker", ar: "\u0648\u064A\u0644 \u0644\u0643\u0644 \u0647\u0645\u0632\u0629 \u0644\u0645\u0632\u0629", id: "Kecelakaan bagi setiap pencela dan penghina", tr: "Her alaya al\u0131p \xE7eki\u015Ftirene yaz\u0131klar olsun", zh: "\u7978\u54C9\uFF0C\u4E00\u5207\u5632\u8BBD\u6BC1\u8C24\u8005", sw: "Ole kwa kila mtukutu na mkejeli", so: "Ceeb ku tahay kii Aflagaadeynayay", bs: "Te\u0161ko svakom klevetnik-ruga\u010Du", sq: "Mjer\xEB \xE7do grindavec dhe tall\xEBs", ru: "\u0413\u043E\u0440\u0435 \u0432\u0441\u044F\u043A\u043E\u043C\u0443 \u0445\u0443\u043B\u0438\u0442\u0435\u043B\u044E \u0438 \u043D\u0430\u0441\u043C\u0435\u0448\u043D\u0438\u043A\u0443", ur: "\u06C1\u0631 \u0637\u0639\u0646\u06C1 \u062F\u06CC\u0646\u06D2 \u0648\u0627\u0644\u06D2 \u0639\u06CC\u0628 \u0644\u06AF\u0627\u0646\u06D2 \u0648\u0627\u0644\u06D2 \u06A9\u06D2 \u0644\u06CC\u06D2 \u062E\u0631\u0627\u0628\u06CC \u06C1\u06D2", bn: "\u09AA\u09CD\u09B0\u09A4\u09CD\u09AF\u09C7\u0995 \u09A8\u09BF\u09A8\u09CD\u09A6\u09C1\u0995 \u0993 \u09AA\u09B0\u09BF\u09B9\u09BE\u09B8\u0995\u09BE\u09B0\u09C0\u09B0 \u099C\u09A8\u09CD\u09AF \u09A6\u09C1\u09B0\u09CD\u09AD\u09CB\u0997", ms: "Celakalah setiap pencela dan pengumpat" },
        surahAyah: "\u0627\u0644\u0647\u0645\u0632\u0629:1",
        ayahNumber: 1,
        hint: "\u0645\u0646 \u064A\u0643\u0633\u0631 \u0634\u062E\u0635\u064A\u0629 \u0627\u0644\u0622\u062E\u0631\u064A\u0646 \u0628\u0627\u0644\u0627\u0633\u062A\u0647\u0632\u0627\u0621 \u0648\u0627\u0644\u063A\u064A\u0628\u0629",
        correctVerse: "\u0648\u064E\u064A\u0652\u0644\u064C \u0644\u0650\u0651\u0643\u064F\u0644\u0650\u0651 \u0647\u064F\u0645\u064E\u0632\u064E\u0629\u064D \u0644\u064F\u0651\u0645\u064E\u0632\u064E\u0629\u064D",
        correctVerseMeaning: "Woe to every scorner and mocker",
        options: [{ text: "\u0627\u0644\u0652\u0647\u064F\u0645\u064E\u0632\u064E\u0629\u0650", isCorrect: true }, { text: "\u0627\u0644\u0644\u064F\u0651\u0645\u064E\u0632\u064E\u0629\u0650", isCorrect: false }, { text: "\u0627\u0644\u0652\u0643\u064E\u0627\u0630\u0650\u0628\u0650", isCorrect: false }, { text: "\u0627\u0644\u0638\u064E\u0651\u0627\u0644\u0650\u0645\u0650", isCorrect: false }]
