        surahEn: "Al-Fil",
        targetWord: "\u0627\u0644\u0652\u0641\u0650\u064A\u0644\u0650",
        targetWordMeaning: "The Elephant",
        targetWordTranslations: { en: "The Elephant", ar: "\u0627\u0644\u0641\u064A\u0644 \u2014 \u0627\u0644\u062D\u064A\u0648\u0627\u0646 \u0627\u0644\u0636\u062E\u0645", id: "Gajah", tr: "Fil", zh: "\u5927\u8C61", sw: "Tembo", so: "Maroodi", bs: "Slon", sq: "Elefanti", ru: "\u0421\u043B\u043E\u043D", ur: "\u06C1\u0627\u062A\u06BE\u06CC", bn: "\u09B9\u09BE\u09A4\u09BF", ms: "Gajah" },
        correctVerseMeaningTranslations: { en: "Have you not considered how your Lord dealt with the companions of the elephant", ar: "\u0623\u0644\u0645 \u062A\u0631 \u0643\u064A\u0641 \u0641\u0639\u0644 \u0631\u0628\u0643 \u0628\u0623\u0635\u062D\u0627\u0628 \u0627\u0644\u0641\u064A\u0644", id: "Apakah kamu tidak memperhatikan bagaimana Tuhanmu berbuat terhadap pasukan gajah", tr: "Rabbin fil sahiplerine nas\u0131l yapt\u0131 g\xF6rmedin mi", zh: "\u4F60\u6CA1\u6709\u770B\u5230\u4F60\u7684\u4E3B\u5982\u4F55\u5BF9\u5F85\u8C61\u4E3B\u5417", sw: "Je, hukuona jinsi Mola wako alivyotenda kwa watu wa tembo", so: "Miyaadan arkin siduu Rabbigaagu u galay Asxaabal Fiilka", bs: "Zar ne vidi\u0161 kako je Gospodar tvoj postupio s vlasnicima slona", sq: "A nuk e ke par\xEB se si Zoti yt veproi me shok\xEBt e elefantit", ru: "\u0420\u0430\u0437\u0432\u0435 \u0442\u044B \u043D\u0435 \u0432\u0438\u0434\u0435\u043B, \u043A\u0430\u043A \u043F\u043E\u0441\u0442\u0443\u043F\u0438\u043B \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0441 \u0445\u043E\u0437\u044F\u0435\u0432\u0430\u043C\u0438 \u0441\u043B\u043E\u043D\u0430", ur: "\u06A9\u06CC\u0627 \u0622\u067E \u0646\u06D2 \u0646\u06C1\u06CC\u06BA \u062F\u06CC\u06A9\u06BE\u0627 \u06A9\u06C1 \u0622\u067E \u06A9\u06D2 \u0631\u0628 \u0646\u06D2 \u06C1\u0627\u062A\u06BE\u06CC \u0648\u0627\u0644\u0648\u06BA \u06A9\u06D2 \u0633\u0627\u062A\u06BE \u06A9\u06CC\u0627 \u06A9\u06CC\u0627", bn: "\u09A4\u09C1\u09AE\u09BF \u0995\u09BF \u09A6\u09C7\u0996\u09A8\u09BF \u09A4\u09CB\u09AE\u09BE\u09B0 \u09B0\u09AC \u09B9\u09BE\u09A4\u09C0\u09AC\u09BE\u09B9\u09BF\u09A8\u09C0\u09B0 \u09B8\u09BE\u09A5\u09C7 \u0995\u09C0\u09B0\u09C2\u09AA \u0995\u09B0\u09B2\u09C7\u09A8", ms: "Apakah kamu tidak memperhatikan bagaimana Tuhanmu berbuat terhadap pasukan gajah" },
        surahAyah: "\u0627\u0644\u0641\u064A\u0644:1",
        ayahNumber: 1,
        hint: "\u0627\u0644\u062D\u064A\u0648\u0627\u0646 \u0627\u0644\u0636\u062E\u0645 \u0627\u0644\u0630\u064A \u062C\u0627\u0621 \u0628\u0647 \u0623\u0628\u0631\u0647\u0629 \u0644\u0647\u062F\u0645 \u0627\u0644\u0643\u0639\u0628\u0629",
        correctVerse: "\u0623\u064E\u0644\u064E\u0645\u0652 \u062A\u064E\u0631\u064E \u0643\u064E\u064A\u0652\u0641\u064E \u0641\u064E\u0639\u064E\u0644\u064E \u0631\u064E\u0628\u064F\u0651\u0643\u064E \u0628\u0650\u0623\u064E\u0635\u0652\u062D\u064E\u0627\u0628\u0650 \u0627\u0644\u0652\u0641\u0650\u064A\u0644\u0650",
        correctVerseMeaning: "Have you not considered how your Lord dealt with the companions of the elephant",
        options: [{ text: "\u0627\u0644\u0652\u0641\u0650\u064A\u0644\u0650", isCorrect: true }, { text: "\u0627\u0644\u0652\u062D\u064E\u062C\u064E\u0631\u0650", isCorrect: false }, { text: "\u0627\u0644\u0637\u064E\u0651\u064A\u0652\u0631\u0650", isCorrect: false }, { text: "\u0627\u0644\u0631\u0650\u0651\u064A\u062D\u0650", isCorrect: false }]
