        targetWordTranslations: { en: "Flocks / Groups (of birds)", ar: "\u062C\u0645\u0627\u0639\u0627\u062A \u0645\u0646 \u0627\u0644\u0637\u064A\u0648\u0631", id: "Kawanan burung", tr: "S\xFCr\xFCler (ku\u015F\uB5BC)", zh: "\u6210\u7FA4\u7684\u9E1F", sw: "Makundi ya ndege", so: "Xoolaahda Shimbirraha", bs: "Jata (ptica)", sq: "Tufat (zogjve)", ru: "\u0421\u0442\u0430\u0438 (\u043F\u0442\u0438\u0446)", ur: "\u067E\u0631\u0646\u062F\u0648\u06BA \u06A9\u06D2 \u062C\u06BE\u0646\u0688", bn: "\u09AA\u09BE\u0996\u09BF\u09B0 \u099D\u09BE\u0981\u0995", ms: "Sekumpulan burung" },
        correctVerseMeaningTranslations: { en: "And He sent against them birds in flocks", ar: "\u0648\u0623\u0631\u0633\u0644 \u0639\u0644\u064A\u0647\u0645 \u0637\u064A\u0631\u0627\u064B \u0623\u0628\u0627\u0628\u064A\u0644", id: "Dan Dia mengirimkan kepada mereka burung yang berbondong-bondong", tr: "Ve \xFCzerlerine s\xFCr\xFC s\xFCr\xFC ku\u015Flar g\xF6nderdi", zh: "\u4ED6\u6D3E\u9063\u6210\u7FA4\u7684\u9E1F\u653B\u51FB\u4ED6\u4EEC", sw: "Na akawapelekea ndege kwa makundi", so: "Wuxuuna u diray Shimbirraha Xoolaah", bs: "I poslao je na njih ptice u jatima", sq: "Dhe d\xEBrgoi kund\xEBr tyre zogj n\xEB tufa", ru: "\u0418 \u043F\u043E\u0441\u043B\u0430\u043B \u041E\u043D \u043D\u0430 \u043D\u0438\u0445 \u043F\u0442\u0438\u0446 \u0441\u0442\u0430\u044F\u043C\u0438", ur: "\u0627\u0648\u0631 \u0627\u0633 \u0646\u06D2 \u0627\u0646 \u067E\u0631 \u067E\u0631\u0646\u062F\u0648\u06BA \u06A9\u06D2 \u062C\u06BE\u0646\u0688 \u0628\u06BE\u06CC\u062C\u06D2", bn: "\u09A4\u09BF\u09A8\u09BF \u09A4\u09BE\u09A6\u09C7\u09B0 \u0989\u09AA\u09B0 \u09AA\u09BE\u0996\u09BF\u09B0 \u099D\u09BE\u0981\u0995 \u09AA\u09BE\u09A0\u09BE\u09B2\u09C7\u09A8", ms: "Dan Dia mengirimkan kepada mereka burung yang berbondong-bondong" },
        surahAyah: "\u0627\u0644\u0641\u064A\u0644:3",
        ayahNumber: 3,
        hint: "\u062C\u0645\u0648\u0639 \u0643\u062B\u064A\u0631\u0629 \u0645\u0646 \u0627\u0644\u0637\u064A\u0648\u0631 \u062C\u0627\u0621\u062A \u062A\u062D\u0645\u0644 \u0627\u0644\u062D\u062C\u0627\u0631\u0629",
        correctVerse: "\u0648\u064E\u0623\u064E\u0631\u0652\u0633\u064E\u0644\u064E \u0639\u064E\u0644\u064E\u064A\u0652\u0647\u0650\u0645\u0652 \u0637\u064E\u064A\u0652\u0631\u064B\u0627 \u0623\u064E\u0628\u064E\u0627\u0628\u0650\u064A\u0644\u064E",
        correctVerseMeaning: "And He sent against them birds in flocks",
        options: [{ text: "\u0623\u064E\u0628\u064E\u0627\u0628\u0650\u064A\u0644\u064E", isCorrect: true }, { text: "\u0637\u064E\u064A\u0652\u0631\u064B\u0627", isCorrect: false }, { text: "\u0633\u0650\u062C\u0650\u0651\u064A\u0644\u064D", isCorrect: false }, { text: "\u0639\u064E\u0635\u0652\u0641\u064D", isCorrect: false }]
