        targetWordTranslations: { en: "The Quraysh (Arab Tribe)", ar: "\u0642\u0628\u064A\u0644\u0629 \u0642\u0631\u064A\u0634 \u0623\u0647\u0644 \u0645\u0643\u0629", id: "Suku Quraisy", tr: "Kurey\u015F Kabilesi", zh: "\u53E4\u83B1\u4EC0\u90E8\u843D", sw: "Kabila la Qureshi", so: "Qabiilkii Quraysh", bs: "Pleme Kurej\u0161", sq: "Fisi Kurejsh", ru: "\u041A\u0443\u0440\u0430\u0439\u0448\u0438\u0442\u044B (\u0430\u0440\u0430\u0431\u0441\u043A\u043E\u0435 \u043F\u043B\u0435\u043C\u044F)", ur: "\u0642\u0628\u06CC\u0644\u06C1 \u0642\u0631\u06CC\u0634", bn: "\u0995\u09C1\u09B0\u09BE\u0987\u09B6 \u0997\u09CB\u09A4\u09CD\u09B0", ms: "Suku Quraisy" },
        correctVerseMeaningTranslations: { en: "For the accustomed security of the Quraysh", ar: "\u0644\u0625\u064A\u0644\u0627\u0641 \u0642\u0631\u064A\u0634", id: "Karena kebiasaan suku Quraisy", tr: "Kurey\u015F'in al\u0131\u015F\u0131kl\u0131\u011F\u0131 i\xE7in", zh: "\u7531\u4E8E\u53E4\u83B1\u4EC0\u4EBA\u7684\u60EF\u4F8B", sw: "Kwa ajili ya mwelekeo wa Qureshi", so: "Cidhibaarka Quraysh awgeed", bs: "Zbog sporazuma Kurej\u0161a", sq: "P\xEBr shkak t\xEB m\xEBsymjes s\xEB Kurejsh\xEBve", ru: "\u0420\u0430\u0434\u0438 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u041A\u0443\u0440\u0430\u0439\u0448\u0438\u0442\u043E\u0432", ur: "\u0642\u0631\u06CC\u0634 \u06A9\u06CC \u0627\u0644\u0641\u062A \u06A9\u06CC \u0628\u062F\u0648\u0644\u062A", bn: "\u0995\u09C1\u09B0\u09BE\u0987\u09B6\u09A6\u09C7\u09B0 \u09AA\u09B0\u09BF\u099A\u09BF\u09A4\u09BF\u09B0 \u0995\u09BE\u09B0\u09A3\u09C7", ms: "Kerana keselamatan yang telah biasa bagi Quraisy" },
