        correctVerseMeaningTranslations: { en: "Have you seen the one who denies the Recompense?", ar: "\u0623\u0631\u0623\u064A\u062A \u0627\u0644\u0630\u064A \u064A\u0643\u0630\u0651\u0628 \u0628\u0627\u0644\u062F\u064A\u0646", id: "Tahukah kamu orang yang mendustakan agama?", tr: "Dini yalanlayan kimseyi g\xF6rd\xFCn m\xFC?", zh: "\u4F60\u89C1\u8FC7\u5426\u8BA4\u62A5\u5E94\u7684\u4EBA\u5417\uFF1F", sw: "Je, umemuona anayekanusha Dini?", so: "Miyaad aragtay Kii beeniyay Diinta?", bs: "Zar ne vidi\u0161 onoga koji pori\u010Deto vjeru?", sq: "A e ke par\xEB at\xEB q\xEB mohon Fen\xEB?", ru: "\u0412\u0438\u0434\u0435\u043B \u043B\u0438 \u0442\u044B \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043E\u0442\u0440\u0438\u0446\u0430\u0435\u0442 \u0432\u0435\u0440\u0443?", ur: "\u06A9\u06CC\u0627 \u062A\u0645 \u0646\u06D2 \u0627\u0633\u06D2 \u062F\u06CC\u06A9\u06BE\u0627 \u062C\u0648 \u062F\u06CC\u0646 \u06A9\u0648 \u062C\u06BE\u0679\u0644\u0627\u062A\u0627 \u06C1\u06D2\u061F", bn: "\u09A4\u09C1\u09AE\u09BF \u0995\u09BF \u09A4\u09BE\u0995\u09C7 \u09A6\u09C7\u0996\u09C7\u099B \u09AF\u09C7 \u09A6\u09CD\u09AC\u09C0\u09A8\u0995\u09C7 \u0985\u09B8\u09CD\u09AC\u09C0\u0995\u09BE\u09B0 \u0995\u09B0\u09C7?", ms: "Tahukah kamu orang yang mendustakan agama?" },
