        correctVerseMeaningTranslations: { en: "And withhold simple assistance", ar: "\u0648\u064A\u0645\u0646\u0639\u0648\u0646 \u0627\u0644\u0645\u0627\u0639\u0648\u0646", id: "Dan tidak mau memberikan bantuan sederhana", tr: "Ve k\xFC\xE7\xFCk yard\u0131mlar\u0131 bile engellerler", zh: "\u751A\u81F3\u62D2\u7EDD\u7ED9\u4E88\u65E5\u7528\u5C0F\u7269", sw: "Na wanazuia msaada mdogo", so: "Waxayna joojiyaan Kaalantu Yar", bs: "I uskra\u0107uju malu pomo\u0107", sq: "Dhe pengojn\xEB ndihmat e vogla", ru: "\u0418 \u043E\u0442\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u0432 \u043C\u0430\u043B\u0435\u0439\u0448\u0435\u0439 \u043F\u043E\u043C\u043E\u0449\u0438", ur: "\u0627\u0648\u0631 \u0645\u0639\u0645\u0648\u0644\u06CC \u0686\u06CC\u0632\u06CC\u06BA \u0628\u06BE\u06CC \u0646\u06C1\u06CC\u06BA \u062F\u06CC\u062A\u06D2", bn: "\u098F\u09AC\u0982 \u099B\u09CB\u099F \u09B8\u09BE\u09B9\u09BE\u09AF\u09CD\u09AF\u0993 \u09AA\u09CD\u09B0\u09A6\u09BE\u09A8 \u0995\u09B0\u09C7 \u09A8\u09BE", ms: "Dan tidak mau memberikan bantuan yang kecil" },
        surahAyah: "\u0627\u0644\u0645\u0627\u0639\u0648\u0646:7",
        ayahNumber: 7,
        hint: "\u0627\u0644\u0623\u0634\u064A\u0627\u0621 \u0627\u0644\u0628\u0633\u064A\u0637\u0629 \u0643\u0627\u0644\u0645\u0644\u062D \u0648\u0627\u0644\u0642\u0650\u062F\u0631 \u0627\u0644\u062A\u064A \u064A\u064F\u0639\u064A\u0631\u0647\u0627 \u0627\u0644\u062C\u064A\u0631\u0627\u0646",
        correctVerse: "\u0648\u064E\u064A\u064E\u0645\u0652\u0646\u064E\u0639\u064F\u0648\u0646\u064E \u0627\u0644\u0652\u0645\u064E\u0627\u0639\u064F\u0648\u0646\u064E",
        correctVerseMeaning: "And withhold simple assistance",
        options: [{ text: "\u0627\u0644\u0652\u0645\u064E\u0627\u0639\u064F\u0648\u0646\u064E", isCorrect: true }, { text: "\u0627\u0644\u0635\u064E\u0651\u0644\u0627\u0629\u064E", isCorrect: false }, { text: "\u0627\u0644\u0632\u064E\u0651\u0643\u064E\u0627\u0629\u064E", isCorrect: false }, { text: "\u0627\u0644\u0635\u064E\u0651\u062F\u064E\u0642\u064E\u0629\u064E", isCorrect: false }]
