        correctVerseMeaningTranslations: { en: "For you is your religion, and for me is my religion", ar: "\u0644\u0643\u0645 \u062F\u064A\u0646\u0643\u0645 \u0648\u0644\u064A \u062F\u064A\u0646", id: "Untukmulah agamamu dan untukkulah agamaku", tr: "Sizin dininiz size, benim dinim bana", zh: "\u4F60\u4EEC\u6709\u4F60\u4EEC\u7684\u5B97\u6559\uFF0C\u6211\u6709\u6211\u7684\u5B97\u6559", sw: "Dini yako ni yako, na dini yangu ni yangu", so: "Diintaadda kuu tahay adiga, diinteyda ii tahay aniga", bs: "Vi imate svoju vjeru, a ja svoju", sq: "Juve e keni fen\xEB tuaj, mua e kam fen\xEB time", ru: "\u0412\u0430\u043C \u0432\u0430\u0448\u0430 \u0432\u0435\u0440\u0430, \u0438 \u043C\u043D\u0435 \u043C\u043E\u044F \u0432\u0435\u0440\u0430", ur: "\u062A\u0645\u06C1\u0627\u0631\u06D2 \u0644\u06CC\u06D2 \u062A\u0645\u06C1\u0627\u0631\u0627 \u062F\u06CC\u0646 \u0627\u0648\u0631 \u0645\u06CC\u0631\u06D2 \u0644\u06CC\u06D2 \u0645\u06CC\u0631\u0627 \u062F\u06CC\u0646", bn: "\u09A4\u09CB\u09AE\u09BE\u09A6\u09C7\u09B0 \u099C\u09A8\u09CD\u09AF \u09A4\u09CB\u09AE\u09BE\u09A6\u09C7\u09B0 \u09A7\u09B0\u09CD\u09AE \u098F\u09AC\u0982 \u0986\u09AE\u09BE\u09B0 \u099C\u09A8\u09CD\u09AF \u0986\u09AE\u09BE\u09B0 \u09A7\u09B0\u09CD\u09AE", ms: "Bagi kamu agamamu dan bagiku agamaku" },
        surahAyah: "\u0627\u0644\u0643\u0627\u0641\u0631\u0648\u0646:6",
