        targetWordTranslations: { en: "The Victory / Divine Help", ar: "\u0627\u0644\u0646\u0635\u0631 \u0648\u0627\u0644\u0641\u062A\u062D \u0627\u0644\u0625\u0644\u0647\u064A", id: "Pertolongan / Kemenangan", tr: "Zafer / \u0130lahi Yard\u0131m", zh: "\u80DC\u5229/\u795E\u52A9", sw: "Ushindi / Msaada", so: "Guushu / Gargaarka", bs: "Pobjeda / Pomo\u0107", sq: "Fitorja / Ndihma Hyjnore", ru: "\u041F\u043E\u0431\u0435\u0434\u0430 / \u041F\u043E\u043C\u043E\u0449\u044C \u0410\u043B\u043B\u0430\u0445\u0430", ur: "\u0641\u062A\u062D \u0648 \u0646\u0635\u0631\u062A", bn: "\u09AC\u09BF\u099C\u09AF\u09BC/\u09B8\u09BE\u09B9\u09BE\u09AF\u09CD\u09AF", ms: "Pertolongan / Kemenangan" },
        correctVerseMeaningTranslations: { en: "When the victory of Allah has come and the conquest", ar: "\u0625\u0630\u0627 \u062C\u0627\u0621 \u0646\u0635\u0631 \u0627\u0644\u0644\u0647 \u0648\u0627\u0644\u0641\u062A\u062D", id: "Apabila telah datang pertolongan Allah dan kemenangan", tr: "Allah'\u0131n yard\u0131m\u0131 ve fetih geldi\u011Finde", zh: "\u5F53\u771F\u4E3B\u7684\u5E2E\u52A9\u548C\u80DC\u5229\u6765\u4E34\u65F6", sw: "Msaada wa Allah na ushindi utakapofika", so: "Gargaarkii Eebe iyo Furitaankii markay yimaadaan", bs: "Kada do\u0111e Allahova pomo\u0107 i osvajanje", sq: "Kur t\xEB vij\xEB ndihma e Allahut dhe \xE7lirimi", ru: "\u041A\u043E\u0433\u0434\u0430 \u043F\u0440\u0438\u0434\u0451\u0442 \u043F\u043E\u043C\u043E\u0449\u044C \u0410\u043B\u043B\u0430\u0445\u0430 \u0438 \u043F\u043E\u0431\u0435\u0434\u0430", ur: "\u062C\u0628 \u0627\u0644\u0644\u06C1 \u06A9\u06CC \u0645\u062F\u062F \u0627\u0648\u0631 \u0641\u062A\u062D \u0622 \u062C\u0627\u0626\u06D2", bn: "\u09AF\u0996\u09A8 \u0986\u09B2\u09CD\u09B2\u09BE\u09B9\u09B0 \u09B8\u09BE\u09B9\u09BE\u09AF\u09CD\u09AF \u098F\u09AC\u0982 \u09AC\u09BF\u099C\u09AF\u09BC \u0986\u09B8\u09C7", ms: "Apabila datang pertolongan Allah dan kemenangan" },
        surahAyah: "\u0627\u0644\u0646\u0635\u0631:1",
        ayahNumber: 1,
        hint: "\u0627\u0644\u062A\u0623\u064A\u064A\u062F \u0627\u0644\u0625\u0644\u0647\u064A \u0648\u0627\u0644\u063A\u0644\u0628\u0629 \u0639\u0644\u0649 \u0627\u0644\u0623\u0639\u062F\u0627\u0621",
        correctVerse: "\u0625\u0650\u0630\u064E\u0627 \u062C\u064E\u0627\u0621\u064E \u0646\u064E\u0635\u0652\u0631\u064F \u0627\u0644\u0644\u064E\u0651\u0647\u0650 \u0648\u064E\u0627\u0644\u0652\u0641\u064E\u062A\u0652\u062D\u064F",
        correctVerseMeaning: "When the victory of Allah has come and the conquest",
        options: [{ text: "\u0627\u0644\u0646\u064E\u0651\u0635\u0652\u0631\u064F", isCorrect: true }, { text: "\u0627\u0644\u0652\u0641\u064E\u062A\u0652\u062D\u064F", isCorrect: false }, { text: "\u0627\u0644\u0631\u064E\u0651\u062D\u0652\u0645\u064E\u0629\u064F", isCorrect: false }, { text: "\u0627\u0644\u0652\u0645\u064E\u063A\u0652\u0641\u0650\u0631\u064E\u0629\u064F", isCorrect: false }]
