        targetWordTranslations: { en: "In Multitudes / Groups", ar: "\u062C\u0645\u0627\u0639\u0627\u062A \u0648\u0632\u0645\u0631\u0627\u064B \u0643\u062B\u064A\u0631\u0629", id: "Berbondong-bondong", tr: "B\xF6l\xFCk b\xF6l\xFCk / Kalabal\u0131k gruplar halinde", zh: "\u6210\u7FA4\u7ED3\u961F", sw: "Makundi makundi", so: "Kooxo Kooxo", bs: "U grupama", sq: "N\xEB grupe / N\xEB tufa", ru: "\u0422\u043E\u043B\u043F\u0430\u043C\u0438 / \u0413\u0440\u0443\u043F\u043F\u0430\u043C\u0438", ur: "\u0641\u0648\u062C \u062F\u0631 \u0641\u0648\u062C / \u06AF\u0631\u0648\u06C1 \u06AF\u0631\u0648\u06C1", bn: "\u09A6\u09B2\u09C7 \u09A6\u09B2\u09C7", ms: "Berbondong-bondong" },
        correctVerseMeaningTranslations: { en: "And you see the people entering the religion of Allah in multitudes", ar: "\u0648\u0631\u0623\u064A\u062A \u0627\u0644\u0646\u0627\u0633 \u064A\u062F\u062E\u0644\u0648\u0646 \u0641\u064A \u062F\u064A\u0646 \u0627\u0644\u0644\u0647 \u0623\u0641\u0648\u0627\u062C\u0627\u064B", id: "Dan kamu melihat manusia masuk agama Allah dengan berbondong-bondong", tr: "\u0130nsanlar\u0131n Allah'\u0131n dinine b\xF6l\xFCk b\xF6l\xFCk girdi\u011Fini g\xF6rd\xFC\u011F\xFCnde", zh: "\u4F60\u770B\u5230\u4EBA\u4EEC\u6210\u7FA4\u7ED3\u961F\u5730\u8FDB\u5165\u771F\u4E3B\u7684\u5B97\u6559", sw: "Ukiona watu wakiingia katika dini ya Allah kwa makundi", so: "Dadkana arkaysaa oo ay ku galeyaan Diinta Eebe Kooxo Kooxo", bs: "I vidi\u0161 ljude kako grupno ulaze u Allahovu vjeru", sq: "Dhe shoh\xEBsh njer\xEBzit duke hyr\xEB n\xEB fen\xEB e Allahut n\xEB tufa", ru: "\u0418 \u0443\u0432\u0438\u0434\u0438\u0448\u044C, \u043A\u0430\u043A \u043B\u044E\u0434\u0438 \u0442\u043E\u043B\u043F\u0430\u043C\u0438 \u0432\u0445\u043E\u0434\u044F\u0442 \u0432 \u0440\u0435\u043B\u0438\u0433\u0438\u044E \u0410\u043B\u043B\u0430\u0445\u0430", ur: "\u0627\u0648\u0631 \u062A\u0645 \u062F\u06CC\u06A9\u06BE\u0648 \u06A9\u06C1 \u0644\u0648\u06AF \u0641\u0648\u062C \u062F\u0631 \u0641\u0648\u062C \u0627\u0644\u0644\u06C1 \u06A9\u06D2 \u062F\u06CC\u0646 \u0645\u06CC\u06BA \u062F\u0627\u062E\u0644 \u06C1\u0648 \u0631\u06C1\u06D2 \u06C1\u06CC\u06BA", bn: "\u098F\u09AC\u0982 \u09A4\u09C1\u09AE\u09BF \u09A6\u09C7\u0996\u09CB \u09AE\u09BE\u09A8\u09C1\u09B7 \u09A6\u09B2\u09C7 \u09A6\u09B2\u09C7 \u0986\u09B2\u09CD\u09B2\u09BE\u09B9\u09B0 \u09A7\u09B0\u09CD\u09AE\u09C7 \u09AA\u09CD\u09B0\u09AC\u09C7\u09B6 \u0995\u09B0\u099B\u09C7", ms: "Dan kamu melihat manusia masuk agama Allah berbondong-bondong" },
        surahAyah: "\u0627\u0644\u0646\u0635\u0631:2",
        ayahNumber: 2,
        hint: "\u062C\u0645\u0648\u0639 \u0643\u062B\u064A\u0631\u0629 \u0645\u0646 \u0627\u0644\u0646\u0627\u0633 \u062A\u062F\u062E\u0644 \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u062F\u0641\u0639\u0629 \u0648\u0627\u062D\u062F\u0629",
        correctVerse: "\u0648\u064E\u0631\u064E\u0623\u064E\u064A\u0652\u062A\u064E \u0627\u0644\u0646\u064E\u0651\u0627\u0633\u064E \u064A\u064E\u062F\u0652\u062E\u064F\u0644\u064F\u0648\u0646\u064E \u0641\u0650\u064A \u062F\u0650\u064A\u0646\u0650 \u0627\u0644\u0644\u064E\u0651\u0647\u0650 \u0623\u064E\u0641\u0652\u0648\u064E\u0627\u062C\u064B\u0627",
        correctVerseMeaning: "And you see the people entering the religion of Allah in multitudes",
        options: [{ text: "\u0623\u064E\u0641\u0652\u0648\u064E\u0627\u062C\u064B\u0627", isCorrect: true }, { text: "\u062C\u064E\u0645\u064E\u0627\u0639\u064E\u0627\u062A\u064D", isCorrect: false }, { text: "\u0627\u0644\u0646\u064E\u0651\u0627\u0633\u064E", isCorrect: false }, { text: "\u0648\u064E\u0627\u062D\u0650\u062F\u064B\u0627", isCorrect: false }]
