        targetWordTranslations: { en: "May It Perish / Be Doomed", ar: "\u062E\u0633\u0631\u062A \u0648\u0647\u0644\u0643\u062A", id: "Binasalah / Hancurlah", tr: "Mahvolsun / Kahrolsun", zh: "\u706D\u4EA1/\u8BC5\u5492", sw: "Na ianguke / Iangamie", so: "Ha lumiyee", bs: "Neka propadne / Propalo mu", sq: "Humboft\xEB / D\xEBmtoft\xEB", ru: "\u0414\u0430 \u043F\u043E\u0433\u0438\u0431\u043D\u0443\u0442 / \u0414\u0430 \u043E\u0442\u0441\u043E\u0445\u043D\u0443\u0442", ur: "\u0679\u0648\u0679 \u062C\u0627\u0626\u06CC\u06BA / \u06C1\u0644\u0627\u06A9 \u06C1\u0648\u06BA", bn: "\u09A7\u09CD\u09AC\u0982\u09B8 \u09B9\u09CB\u0995", ms: "Binasalah / Hancurlah" },
        correctVerseMeaningTranslations: { en: "May the hands of Abu Lahab be ruined and ruined is he", ar: "\u062A\u0628\u0651\u062A \u064A\u062F\u0627 \u0623\u0628\u064A \u0644\u0647\u0628 \u0648\u062A\u0628\u0651", id: "Binasalah kedua tangan Abu Lahab dan binasalah dia", tr: "Ebu Leheb'in elleri kurusun! O da helak oldu zaten", zh: "\u613F\u827E\u535C\xB7\u62C9\u54C8\u5E03\u7684\u53CC\u624B\u6BC1\u706D\uFF0C\u4ED6\u5DF2\u6BC1\u706D\u4E86", sw: "Na zianguke mikono ya Abu Lahab na yeye aangamie", so: "Gacmaha Abi Lahab ha goblobaan oo wuu lumay", bs: "Neka propadnu ruke Ebu Leheba i on sam propao je", sq: "U prishin duart e Ebu Lehebit, dhe ai humbi", ru: "\u0414\u0430 \u043E\u0442\u0441\u043E\u0445\u043D\u0443\u0442 \u0440\u0443\u043A\u0438 \u0410\u0431\u0443 \u041B\u044F\u0445\u0430\u0431\u0430, \u0438 \u043E\u043D \u0441\u0430\u043C \u043F\u043E\u0433\u0438\u0431", ur: "\u0627\u0628\u0648 \u0644\u06C1\u0628 \u06A9\u06D2 \u06C1\u0627\u062A\u06BE \u0679\u0648\u0679\u06CC\u06BA \u0627\u0648\u0631 \u0648\u06C1 \u062E\u0648\u062F \u06C1\u0644\u0627\u06A9 \u06C1\u0648", bn: "\u0986\u09AC\u09C1 \u09B2\u09BE\u09B9\u09BE\u09AC\u09C7\u09B0 \u09B9\u09BE\u09A4 \u09A7\u09CD\u09AC\u0982\u09B8 \u09B9\u09CB\u0995 \u098F\u09AC\u0982 \u09B8\u09C7 \u09A8\u09BF\u099C\u09C7\u0993 \u09A7\u09CD\u09AC\u0982\u09B8 \u09B9\u09CB\u0995", ms: "Binasalah kedua tangan Abu Lahab dan binasalah dia" },
        surahAyah: "\u0627\u0644\u0645\u0633\u062F:1",
        ayahNumber: 1,
        hint: "\u062F\u0639\u0627\u0621 \u0628\u0627\u0644\u0647\u0644\u0627\u0643 \u0648\u0627\u0644\u062E\u0633\u0631\u0627\u0646",
        correctVerse: "\u062A\u064E\u0628\u064E\u0651\u062A\u0652 \u064A\u064E\u062F\u064E\u0627 \u0623\u064E\u0628\u0650\u064A \u0644\u064E\u0647\u064E\u0628\u064D \u0648\u064E\u062A\u064E\u0628\u064E\u0651",
        correctVerseMeaning: "May the hands of Abu Lahab be ruined and ruined is he",
        options: [{ text: "\u062A\u064E\u0628\u064E\u0651\u062A\u0652", isCorrect: true }, { text: "\u064A\u064E\u062F\u064E\u0627", isCorrect: false }, { text: "\u0648\u064E\u062A\u064E\u0628\u064E\u0651", isCorrect: false }, { text: "\u0644\u064E\u0647\u064E\u0628\u064D", isCorrect: false }]
