        correctVerseMeaningTranslations: { en: "And from the evil of the blowers in knots", ar: "\u0648\u0645\u0646 \u0634\u0631 \u0627\u0644\u0646\u0641\u0627\u062B\u0627\u062A \u0641\u064A \u0627\u0644\u0639\u0642\u062F", id: "Dan dari kejahatan peniup buhul-buhul", tr: "D\xFC\u011F\xFCmlere \xFCfleyenlerin \u015Ferrinden", zh: "\u4EE5\u53CA\u5439\u7ED3\u8005\u7684\u6076", sw: "Na shari ya wanaopuliza vifungo", so: "Sharriga Afuufayaasha Xididdaha", bs: "I od zla onih koje pu\u0161u u \u010Dvorove", sq: "Dhe nga e keqja e atyre q\xEB fryjn\xEB n\xEB nyje", ru: "\u0418 \u043E\u0442 \u0437\u043B\u0430 \u0434\u0443\u044E\u0449\u0438\u0445 \u0432 \u0443\u0437\u043B\u044B", ur: "\u0627\u0648\u0631 \u06AF\u0627\u0646\u0679\u06BE\u0648\u06BA \u0645\u06CC\u06BA \u067E\u06BE\u0648\u0646\u06A9\u0646\u06D2 \u0648\u0627\u0644\u06CC\u0648\u06BA \u06A9\u06D2 \u0634\u0631 \u0633\u06D2", bn: "\u098F\u09AC\u0982 \u0997\u09BF\u0981\u099F\u09C7 \u09AB\u09C1\u0981 \u09A6\u09C7\u0993\u09AF\u09BC\u09BE\u09A6\u09C7\u09B0 \u0985\u09A8\u09BF\u09B7\u09CD\u099F \u09A5\u09C7\u0995\u09C7", ms: "Dan dari kejahatan para peniup buhul-buhul" },
