function parseAIResponse(response) {
  try {
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      throw new Error("No JSON found in response");
    }
    const parsed = JSON.parse(jsonMatch[0]);
    const score = Math.max(0, Math.min(100, parsed.score || 0));
    const isCorrect = parsed.isCorrect || false;
    let grade = "incorrect";
    if (isCorrect && score >= 80) {
      grade = "exact_match";
    } else if (isCorrect || score >= 40) {
      grade = "valid_but_less_suitable";
    }
    return {
      isCorrect,
      grade,
      score,
      feedback: parsed.feedback || "No feedback provided",
      suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions : [],
      suggestedAnswer: parsed.suggestedAnswer || void 0,
      connectionExplanation: parsed.connectionExplanation || void 0,
      confidence: Math.max(0, Math.min(1, parsed.confidence || 0.5))
    };
  } catch (error) {
    console.error("Error parsing AI response:", error);
    return {
      isCorrect: false,
      grade: "incorrect",
      score: 0,
      feedback: "Unable to evaluate answer. Please try again.",
      suggestions: ["Check your Arabic spelling and grammar"],
      suggestedAnswer: void 0,
      confidence: 0
    };
  }
}
