async function translateWithRetry(prompt, maxRetries = 3, initialDelay = 1e3, maxOutputTokens = 150) {
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const response = await axios.post(GEMINI_API_URL, {
        contents: [
          {
            parts: [
              {
                text: prompt
              }
            ]
          }
        ],
        generationConfig: {
          temperature: 0.1,
          maxOutputTokens,
          topP: 0.95,
          topK: 40
        }
      });
      return response;
    } catch (error) {
      const isRateLimitError = axios.isAxiosError(error) && (error.response?.status === 429 || error.response?.data?.error?.status === "RESOURCE_EXHAUSTED");
      const isQuotaExhausted = axios.isAxiosError(error) && error.response?.data?.error?.message?.includes("Quota exceeded");
      if (isQuotaExhausted) {
        console.log(`API quota exhausted. Cannot retry - daily limit reached.`);
        throw error;
      }
      if (isRateLimitError && attempt < maxRetries - 1) {
        const delay = initialDelay * Math.pow(2, attempt);
        console.log(`Rate limit hit, retrying in ${delay}ms (attempt ${attempt + 1}/${maxRetries})...`);
        await new Promise((resolve) => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
}
